query:
SELECT 
  COUNT(*) as totale_attivi,
  SUM(CASE WHEN subscribedAt >= '2026-05-10 00:00:00' THEN 1 ELSE 0 END) as lista2,
  SUM(CASE WHEN subscribedAt < '2026-05-10 00:00:00' THEN 1 ELSE 0 END) as lista1
FROM subscribers 
WHERE status = 'active';

SELECT COUNT(*) as unsubscribed FROM subscribers WHERE status = 'unsubscribed';
SELECT COUNT(*) as bounced FROM subscribers WHERE status = 'bounced';

